/* com.erns.coching.search.mapper.CochingEsRawDAO.getList */

SELECT 
	ZZ.*
FROM 
	(	
		SELECT

		FROM T_ES_RAW AA					






				ORDER BY AA.RAW_SEQ


	) ZZ

	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.search.mapper.CochingEsRawDAO.getListVo */

SELECT 
	ZZ.*
FROM 
	(	
		SELECT

		FROM T_ES_RAW AA					






				ORDER BY AA.RAW_SEQ


	) ZZ

	OFFSET #{offset} LIMIT #{rowSize}

    	/* com.erns.coching.search.mapper.CochingEsRawDAO.load */

		SELECT

		FROM T_ES_RAW AA

			AND AA.RAW_SEQ = #{value, jdbcType=INTEGER}

mapper.update:
		/* com.erns.coching.search.mapper.CochingEsRawDAO.dropTable */

    DROP TABLE IF EXISTS t_es_raw;

		commit;

mapper.select:
/* com.erns.coching.search.mapper.CochingEsRawDAO.getListVoForEsRenewIndexItems */
WITH DOC_LIST AS ( /* 문서 코드 리스트 */ SELECT DC.etc1 AS doc_code, MAX(KCD.code_name) AS name_ko, MAX(ECD.code_name) AS name_en FROM ( SELECT DISTINCT grp_code, etc1 FROM T_CODE_INF WHERE grp_code = 'CH003' ) DC LEFT OUTER JOIN T_CODE_INF KCD ON DC.grp_code = KCD.grp_code AND DC.etc1 = KCD.etc1 LEFT OUTER JOIN T_CODE_INF ECD ON DC.grp_code = ECD.grp_code AND DC.etc1 = ECD.etc1 GROUP BY DC.etc1 ORDER BY DC.etc1 )
#{item, jdbcType=INTEGER}
AND COALESCE(RAW_MST.USE_YN, 'Y') = 'Y' AND COALESCE(RAW_MST.DEL_YN, 'N') = 'N' AND COALESCE(PI.DEL_YN, 'N') = 'N' AND SUB_INFO.raw_detail_info_cnt > 0 /* 원료 상세가 없는거 필터링 */

/* com.erns.coching.search.mapper.CochingEsRawDAO.getListVoForEsRenewDeleteItems */
SELECT 'delete' AS job , RAW_MST.raw_seq , RAW_MST.DEL_YN , RAW_MST.USE_YN , PI.DEL_YN , count(RAW_DTL.raw_detail_seq) as detailCount FROM T_RAW_MST RAW_MST /* 원료 마스터 */ LEFT OUTER JOIN T_PARTNER_INF PI /* 파트너사 */ ON RAW_MST.ptn_seq = PI.ptn_seq LEFT OUTER JOIN T_RAW_DETAIL RAW_DTL ON RAW_MST.raw_seq = RAW_DTL.raw_seq AND COALESCE(RAW_DTL.USE_YN, 'Y') = 'Y'
#{item, jdbcType=INTEGER}
GROUP BY RAW_MST.raw_seq , RAW_MST.DEL_YN , RAW_MST.USE_YN , PI.DEL_YN HAVING NOT ( COALESCE(RAW_MST.USE_YN, 'Y') = 'Y' AND COALESCE(RAW_MST.DEL_YN, 'N') = 'N' AND COALESCE(PI.DEL_YN, 'N') = 'N' AND count(RAW_DTL.raw_detail_seq) > 0 /* 원료 상세가 없는거 필터링 */ ) /* ORDER BY RAW_MST.raw_seq */
